(function(){document.addEventListener('DOMContentLoaded',function(){var t=document.querySelector('.carousel-track'),c=document.querySelector('.carousel-container');if(!t||!c)return;var s=Array.from(t.querySelectorAll('.carousel-slide'));if(!s.length)return;var d=document.createElement('div');d.className='carousel-dots';s.forEach(function(_,i){var b=document.createElement('button');b.className='carousel-dot'+(i===0?' active':'');b.setAttribute('aria-label','Slide '+(i+1));b.addEventListener('click',function(){u(i)});d.appendChild(b)});c.after(d);var cur=0;function u(idx){cur=idx;d.querySelectorAll('.carousel-dot').forEach(function(dot,i){dot.classList.toggle('active',i===idx)})}var p=c.querySelector('.carousel-btn.prev'),n=c.querySelector('.carousel-btn.next');if(p)p.addEventListener('click',function(){u(Math.max(0,cur-1))});if(n)n.addEventListener('click',function(){u(Math.min(s.length-1,cur+1))})})})();
